function formatName(user) {
  try {
    console.log('Attempting to format...');
    return user.name.toUpperCase();
  } catch (err) {
    console.log('Error caught: ' + err.name);
    return 'Anonymous';
  } finally {
    console.log('Formatting attempt finished.');
  }
}

console.log(formatName({ name: 'Alice' }));
console.log(formatName(null));

